func buildPageURL(baseURL string, page int, filters repository.AuditFilters) string {
	url := baseURL + "?page=" + itoa(page) + "&pageSize=" + itoa(filters.PageSize)
	if filters.WorkspaceID != nil {
		url += "&workspace_id=" + filters.WorkspaceID.String()
	}
	if filters.TraceID != "" {
		url += "&trace_id=" + filters.TraceID
	}
	if filters.EventType != "" {
		url += "&event_type=" + filters.EventType
	}
	if filters.Start != nil {
		url += "&start=" + filters.Start.Format("2006-01-02")
	}
	if filters.End != nil {
		url += "&end=" + filters.End.Format("2006-01-02")
	}
	return url
}

func buildExportURL(baseURL string, filters repository.AuditFilters) string {
	url := baseURL + "/export?"
	if filters.WorkspaceID != nil {
		url += "workspace_id=" + filters.WorkspaceID.String() + "&"
	}
	if filters.TraceID != "" {
		url += "trace_id=" + filters.TraceID + "&"
	}
	if filters.EventType != "" {
		url += "event_type=" + filters.EventType + "&"
	}
	if filters.Start != nil {
		url += "start=" + filters.Start.Format("2006-01-02") + "&"
	}
	if filters.End != nil {
		url += "end=" + filters.End.Format("2006-01-02") + "&"
	}
	return url
}

func itoa(i int) string {
	if i == 0 {
		return "0"
	}
	s := ""
	for i > 0 {
		s = string(rune('0'+i%10)) + s
		i /= 10
	}
	return s
}

